import { defineComponentSlotStyle } from "@yamada-ui/react"
import { modalStyle } from "../modal"

export const drawerStyle = defineComponentSlotStyle({
  base: {
    ...modalStyle.base,
    body: {
      ...modalStyle.base?.body,
      overflow: "auto",
    },
    content: {
      ...modalStyle.base?.content,
      position: "fixed",
      rounded: "l4",
    },
    dragBar: {
      bg: "bg.subtle",
      position: "absolute",
      rounded: "full",
    },
  },

  props: {
    /**
     * The placement of the drawer.
     *
     * @default 'inline-end'
     */
    placement: {
      "block-end": {
        content: { maxW: "full", roundedBottom: "0" },
        dragBar: {
          left: "50%",
          minH: "2",
          top: "md",
          transform: "translateX(-50%)",
          w: "3xs",
        },
      },
      "block-start": {
        content: { maxW: "full", roundedTop: "0" },
        dragBar: {
          bottom: "md",
          left: "50%",
          minH: "2",
          transform: "translateX(-50%)",
          w: "3xs",
        },
      },
      "inline-end": {
        content: { roundedRight: "0" },
        dragBar: {
          h: "3xs",
          left: "md",
          minW: "2",
          top: "50%",
          transform: "translateY(-50%)",
        },
      },
      "inline-start": {
        content: { roundedLeft: "0" },
        dragBar: {
          h: "3xs",
          minW: "2",
          right: "md",
          top: "50%",
          transform: "translateY(-50%)",
        },
      },
    },
  },

  sizes: {
    xs: { content: { maxW: "xs" } },
    sm: { content: { maxW: "sm" } },
    md: { content: { maxW: "md" } },
    lg: { content: { maxW: "lg" } },
    xl: { content: { maxW: "xl" } },
    "2xl": { content: { maxW: "2xl" } },
    "3xl": { content: { maxW: "3xl" } },
    "4xl": { content: { maxW: "4xl" } },
    "5xl": { content: { maxW: "5xl" } },
    "6xl": { content: { maxW: "6xl" } },
    full: { content: { minH: "dvh", minW: "vw", rounded: "0" } },
  },

  compounds: [
    {
      css: {
        content: {
          pb: "md",
          _after: {
            bg: "bg.panel",
            display: "block",
            h: "dvh",
            left: "0",
            position: "absolute",
            right: "0",
            top: "calc(-100dvh + 1px)",
            w: "full",
          },
        },
      },
      closeOnDrag: true,
      placement: "block-start",
      withDragBar: true,
    },
    {
      css: {
        content: {
          pt: "md",
          _after: {
            bg: "bg.panel",
            bottom: "calc(-100dvh + 1px)",
            display: "block",
            h: "dvh",
            left: "0",
            position: "absolute",
            right: "0",
            w: "full",
          },
        },
      },
      closeOnDrag: true,
      placement: "block-end",
      withDragBar: true,
    },
    {
      css: {
        content: {
          ps: "md",
          _after: {
            bg: "bg.panel",
            bottom: "0",
            display: "block",
            h: "dvh",
            position: "absolute",
            right: "calc(-100% + 1px)",
            top: "0",
            w: "full",
          },
        },
      },
      closeOnDrag: true,
      placement: "inline-end",
      withDragBar: true,
    },
    {
      css: {
        content: {
          pe: "md",
          _after: {
            bg: "bg.panel",
            bottom: "0",
            display: "block",
            h: "dvh",
            left: "calc(-100% + 1px)",
            position: "absolute",
            top: "0",
            w: "full",
          },
        },
      },
      closeOnDrag: true,
      placement: "inline-start",
      withDragBar: true,
    },
  ],

  defaultProps: {
    size: "lg",
    placement: "inline-end",
  },
})

export type DrawerStyle = typeof drawerStyle

import type { FC } from "react"
import { type Locator, locators } from "vitest/browser"
import { a11y, page, render, renderHook } from "#test/browser"
import { Button } from "../button"
import { Drawer } from "./"
import { useDrawer } from "./use-drawer"

declare module "vitest/browser" {
  interface LocatorSelectors {
    getByClassName(className: string): Locator
  }
}

const TestComponent: FC<Drawer.RootProps> = (props) => {
  return (
    <Drawer.Root data-testid="root" {...props}>
      <Drawer.OpenTrigger>
        <Button data-testid="openTrigger">Open Drawer</Button>
      </Drawer.OpenTrigger>

      <Drawer.Overlay data-testid="overlay" />

      <Drawer.Content data-testid="content">
        <Drawer.DragBar data-testid="dragBar" />

        <Drawer.CloseButton data-testid="closeButton" />

        <Drawer.Header data-testid="header">
          <Drawer.Title data-testid="title">ドラゴンボール</Drawer.Title>
        </Drawer.Header>

        <Drawer.Body data-testid="body">
          『ドラゴンボール』（DRAGON
          BALL）は、鳥山明による日本の漫画作品。『週刊少年ジャンプ』（集英社）にて1984年51号から1995年25号まで連載された。世界中に散らばった七つの球をすべて集めると、どんな願いも一つだけ叶えられるという秘宝・ドラゴンボールと、主人公・孫悟空（そん・ごくう）を中心に展開する、「冒険」「夢」「バトル」「友情」などを描いた長編漫画。
        </Drawer.Body>

        <Drawer.Footer data-testid="footer">
          <Drawer.CloseTrigger>
            <Button variant="ghost" data-testid="closeTrigger">
              とじる
            </Button>
          </Drawer.CloseTrigger>
          <Button>Wikipedia</Button>
        </Drawer.Footer>
      </Drawer.Content>
    </Drawer.Root>
  )
}

describe("<Drawer />", () => {
  beforeAll(() => {
    locators.extend({
      getByClassName(className) {
        return `.${className}`
      },
    })
  })

  test("renders component correctly", async () => {
    await a11y(<TestComponent />)
  })

  test("sets `displayName` correctly", () => {
    expect(Drawer.Root.displayName).toBe("DrawerRoot")
    expect(Drawer.Overlay.displayName).toBe("DrawerOverlay")
    expect(Drawer.OpenTrigger.displayName).toBe("DrawerOpenTrigger")
    expect(Drawer.CloseTrigger.displayName).toBe("DrawerCloseTrigger")
    expect(Drawer.CloseButton.displayName).toBe("DrawerCloseButton")
    expect(Drawer.Content.displayName).toBe("DrawerContent")
    expect(Drawer.DragBar.displayName).toBe("DrawerDragBar")
    expect(Drawer.Header.displayName).toBe("DrawerHeader")
    expect(Drawer.Title.displayName).toBe("DrawerTitle")
    expect(Drawer.Body.displayName).toBe("DrawerBody")
    expect(Drawer.Footer.displayName).toBe("DrawerFooter")
  })

  test("sets `className` correctly", async () => {
    await render(<TestComponent open withDragBar />)

    const root = page.getByTestId("root")
    const overlay = page.getByTestId("overlay")
    const content = page.getByTestId("content")
    const dragBar = page.getByTestId("dragBar")
    const closeButton = page.getByTestId("closeButton")
    const header = page.getByTestId("header")
    const title = page.getByTestId("title")
    const body = page.getByTestId("body")
    const footer = page.getByTestId("footer")

    await expect.element(root).toHaveClass("ui-drawer__root")
    await expect.element(overlay).toHaveClass("ui-drawer__overlay")
    await expect.element(content).toHaveClass("ui-drawer__content")
    await expect.element(dragBar).toHaveClass("ui-drawer__drag-bar")
    await expect.element(closeButton).toHaveClass("ui-drawer__close-button")
    await expect.element(header).toHaveClass("ui-drawer__header")
    await expect.element(title).toHaveClass("ui-drawer__title")
    await expect.element(body).toHaveClass("ui-drawer__body")
    await expect.element(footer).toHaveClass("ui-drawer__footer")
  })

  test("sets HTML tag correctly", async () => {
    await render(<TestComponent open withDragBar />)

    const root = page.getByTestId("root")
    const overlay = page.getByTestId("overlay")
    const content = page.getByTestId("content")
    const dragBar = page.getByTestId("dragBar")
    const closeButton = page.getByTestId("closeButton")
    const header = page.getByTestId("header")
    const title = page.getByTestId("title")
    const body = page.getByTestId("body")
    const footer = page.getByTestId("footer")

    expect(root.element().tagName).toBe("DIV")
    expect(overlay.element().tagName).toBe("DIV")
    expect(content.element().tagName).toBe("SECTION")
    expect(dragBar.element().tagName).toBe("DIV")
    expect(closeButton.element().tagName).toBe("BUTTON")
    expect(header.element().tagName).toBe("HEADER")
    expect(title.element().tagName).toBe("H2")
    expect(body.element().tagName).toBe("DIV")
    expect(footer.element().tagName).toBe("FOOTER")
  })

  test("sets aria attributes correctly", async () => {
    await render(<TestComponent open />)

    const openTrigger = page.getByTestId("openTrigger")
    const overlay = page.getByTestId("overlay")
    const content = page.getByTestId("content")
    const closeButton = page.getByTestId("closeButton")
    const title = page.getByTestId("title")
    const body = page.getByTestId("body")
    const closeTrigger = page.getByTestId("closeTrigger")

    await expect.element(openTrigger).toHaveAttribute("aria-controls")
    await expect.element(openTrigger).toHaveAttribute("aria-expanded", "true")
    await expect.element(openTrigger).toHaveAttribute("aria-haspopup", "dialog")
    await expect
      .element(openTrigger)
      .toHaveAttribute("aria-label", "Open modal")
    await expect.element(overlay).toHaveAttribute("aria-hidden", "true")
    await expect.element(content).toHaveAttribute("aria-describedby")
    await expect.element(content).toHaveAttribute("aria-labelledby")
    await expect.element(content).toHaveAttribute("aria-modal", "true")
    await expect.element(content).toHaveAttribute("role", "dialog")
    await expect
      .element(closeButton)
      .toHaveAttribute("aria-label", "Close modal")
    await expect
      .element(closeTrigger)
      .toHaveAttribute("aria-label", "Close modal")
    await expect.element(title).toHaveAttribute("id")
    await expect.element(body).toHaveAttribute("id")
  })

  test("renders shorthand content with title and body", async () => {
    await render(
      <Drawer.Root body="Shorthand Body" open title="Shorthand Title" />,
    )

    await expect.element(page.getByText("Shorthand Title")).toBeInTheDocument()
    await expect.element(page.getByText("Shorthand Body")).toBeInTheDocument()
  })

  test("renders shorthand content with cancel, middle, and success buttons", async () => {
    await render(
      <Drawer.Root
        body="Drawer Body"
        cancel="Cancel"
        middle="Middle"
        open
        success="OK"
        title="Drawer Title"
      />,
    )

    await expect.element(page.getByText("Cancel")).toBeInTheDocument()
    await expect.element(page.getByText("Middle")).toBeInTheDocument()
    await expect.element(page.getByText("OK")).toBeInTheDocument()
  })

  test("calls onCancel callback when cancel button is clicked", async () => {
    const onCancel = vi.fn()
    const { user } = await render(
      <Drawer.Root body="Body" cancel="Cancel" open onCancel={onCancel} />,
    )

    await user.click(page.getByText("Cancel"))
    expect(onCancel).toHaveBeenCalledTimes(1)
  })

  test("calls onMiddle callback when middle button is clicked", async () => {
    const onMiddle = vi.fn()
    const { user } = await render(
      <Drawer.Root body="Body" middle="Middle" open onMiddle={onMiddle} />,
    )

    await user.click(page.getByText("Middle"))
    expect(onMiddle).toHaveBeenCalledTimes(1)
  })

  test("calls onSuccess callback when success button is clicked", async () => {
    const onSuccess = vi.fn()
    const { user } = await render(
      <Drawer.Root body="Body" open success="OK" onSuccess={onSuccess} />,
    )

    await user.click(page.getByText("OK"))
    expect(onSuccess).toHaveBeenCalledTimes(1)
  })

  test("renders default drag bar when closeOnDrag and withDragBar are true", async () => {
    await render(
      <Drawer.Root closeOnDrag open withDragBar>
        <Drawer.Content data-testid="content">
          <Drawer.Body>Content</Drawer.Body>
        </Drawer.Content>
      </Drawer.Root>,
    )

    const contentLocator = page.getByTestId("content")
    const dragBarLocator = contentLocator.getByClassName("ui-drawer__drag-bar")

    await expect.element(contentLocator).toBeInTheDocument()
    await expect.element(dragBarLocator).toBeInTheDocument()
  })

  test("does not render drag bar when closeOnDrag is false", async () => {
    await render(
      <Drawer.Root closeOnDrag={false} open withDragBar>
        <Drawer.Content data-testid="content">
          <Drawer.Body>Content</Drawer.Body>
        </Drawer.Content>
      </Drawer.Root>,
    )

    const contentLocator = page.getByTestId("content")
    const dragBarLocator = contentLocator.getByClassName("ui-drawer__drag-bar")

    await expect.element(contentLocator).toBeInTheDocument()
    await expect.element(dragBarLocator.query()).not.toBeInTheDocument()
  })

  test("renders without overlay when withOverlay is false", async () => {
    await render(
      <Drawer.Root open withOverlay={false}>
        <Drawer.Content>
          <Drawer.Body>Content</Drawer.Body>
        </Drawer.Content>
      </Drawer.Root>,
    )

    await expect.element(page.getByText("Content")).toBeInTheDocument()
    await expect
      .element(page.getByClassName("ui-drawer__overlay").query())
      .not.toBeInTheDocument()
  })

  test("renders with trigger prop", async () => {
    await render(
      <Drawer.Root trigger={<Button>Trigger Button</Button>}>
        <Drawer.Content>
          <Drawer.Body>Content</Drawer.Body>
        </Drawer.Content>
      </Drawer.Root>,
    )

    await expect.element(page.getByText("Trigger Button")).toBeInTheDocument()
  })

  test("renders with placement block-start", async () => {
    await render(
      <Drawer.Root closeOnDrag open placement="block-start">
        <Drawer.Content data-testid="content">
          <Drawer.Body>Content</Drawer.Body>
        </Drawer.Content>
      </Drawer.Root>,
    )

    await expect.element(page.getByTestId("content")).toBeInTheDocument()
  })

  test("renders with placement block-end", async () => {
    await render(
      <Drawer.Root closeOnDrag open placement="block-end">
        <Drawer.Content data-testid="content">
          <Drawer.Body>Content</Drawer.Body>
        </Drawer.Content>
      </Drawer.Root>,
    )

    await expect.element(page.getByTestId("content")).toBeInTheDocument()
  })

  test("renders with placement inline-start", async () => {
    await render(
      <Drawer.Root closeOnDrag open placement="inline-start">
        <Drawer.Content data-testid="content">
          <Drawer.Body>Content</Drawer.Body>
        </Drawer.Content>
      </Drawer.Root>,
    )

    await expect.element(page.getByTestId("content")).toBeInTheDocument()
  })

  test("renders with placement inline-end", async () => {
    await render(
      <Drawer.Root closeOnDrag open placement="inline-end">
        <Drawer.Content data-testid="content">
          <Drawer.Body>Content</Drawer.Body>
        </Drawer.Content>
      </Drawer.Root>,
    )

    await expect.element(page.getByTestId("content")).toBeInTheDocument()
  })

  test("renders shorthand content with header as props object", async () => {
    await render(
      <Drawer.Root
        body="Body Content"
        header={{ children: "Header Content" }}
        open
      />,
    )

    await expect.element(page.getByText("Header Content")).toBeInTheDocument()
    await expect.element(page.getByText("Body Content")).toBeInTheDocument()
  })

  test("renders shorthand content with footer as props object", async () => {
    await render(
      <Drawer.Root
        body="Body Content"
        footer={{ children: "Footer Content" }}
        open
      />,
    )

    await expect.element(page.getByText("Footer Content")).toBeInTheDocument()
  })

  test("closes drawer when cancel button is clicked without onCancel", async () => {
    const onClose = vi.fn()
    const { user } = await render(
      <Drawer.Root body="Body" cancel="Cancel" open onClose={onClose} />,
    )

    await user.click(page.getByText("Cancel"))
    expect(onClose).toHaveBeenCalledWith(undefined)
  })

  test("closes drawer when middle button is clicked without onMiddle", async () => {
    const onClose = vi.fn()
    const { user } = await render(
      <Drawer.Root body="Body" middle="Middle" open onClose={onClose} />,
    )

    await user.click(page.getByText("Middle"))
    expect(onClose).toHaveBeenCalledWith(undefined)
  })

  test("closes drawer when success button is clicked without onSuccess", async () => {
    const onClose = vi.fn()
    const { user } = await render(
      <Drawer.Root body="Body" open success="OK" onClose={onClose} />,
    )

    await user.click(page.getByText("OK"))
    expect(onClose).toHaveBeenCalledWith(undefined)
  })
})

describe("useDrawer", () => {
  const mockEvent = {} as MouseEvent

  test("calls onClose when dragged up with sufficient velocity for block-start", async () => {
    const onClose = vi.fn()
    const { result } = await renderHook(() =>
      useDrawer({
        closeOnDrag: true,
        open: true,
        placement: "block-start",
        onClose,
      }),
    )

    const contentProps = result.current.getContentProps()

    contentProps.onDragEnd?.(mockEvent, {
      delta: { x: 0, y: 0 },
      offset: { x: 0, y: 0 },
      point: { x: 0, y: 0 },
      velocity: { x: 0, y: -200 },
    })

    expect(onClose).toHaveBeenCalledWith(undefined)
  })

  test("calls onClose when dragged up with sufficient offset for block-start", async () => {
    const onClose = vi.fn()
    const { result } = await renderHook(() =>
      useDrawer({
        closeOnDrag: true,
        open: true,
        placement: "block-start",
        onClose,
      }),
    )

    const contentProps = result.current.getContentProps()

    contentProps.onDragEnd?.(mockEvent, {
      delta: { x: 0, y: 0 },
      offset: { x: 0, y: -100 },
      point: { x: 0, y: 0 },
      velocity: { x: 0, y: 0 },
    })

    expect(onClose).toHaveBeenCalledWith(undefined)
  })

  test("does not call onClose when drag is insufficient for block-start", async () => {
    const onClose = vi.fn()
    const { result } = await renderHook(() =>
      useDrawer({
        closeOnDrag: true,
        open: true,
        placement: "block-start",
        onClose,
      }),
    )

    const contentProps = result.current.getContentProps()

    contentProps.onDragEnd?.(mockEvent, {
      delta: { x: 0, y: 0 },
      offset: { x: 0, y: -10 },
      point: { x: 0, y: 0 },
      velocity: { x: 0, y: -10 },
    })

    expect(onClose).not.toHaveBeenCalledWith(undefined)
  })

  test("calls onClose when dragged down with sufficient velocity for block-end", async () => {
    const onClose = vi.fn()
    const { result } = await renderHook(() =>
      useDrawer({
        closeOnDrag: true,
        open: true,
        placement: "block-end",
        onClose,
      }),
    )

    const contentProps = result.current.getContentProps()

    contentProps.onDragEnd?.(mockEvent, {
      delta: { x: 0, y: 0 },
      offset: { x: 0, y: 0 },
      point: { x: 0, y: 0 },
      velocity: { x: 0, y: 200 },
    })

    expect(onClose).toHaveBeenCalledWith(undefined)
  })

  test("calls onClose when dragged down with sufficient offset for block-end", async () => {
    const onClose = vi.fn()
    const { result } = await renderHook(() =>
      useDrawer({
        closeOnDrag: true,
        open: true,
        placement: "block-end",
        onClose,
      }),
    )

    const contentProps = result.current.getContentProps()

    contentProps.onDragEnd?.(mockEvent, {
      delta: { x: 0, y: 0 },
      offset: { x: 0, y: 100 },
      point: { x: 0, y: 0 },
      velocity: { x: 0, y: 0 },
    })

    expect(onClose).toHaveBeenCalledWith(undefined)
  })

  test("calls onClose when dragged left with sufficient velocity for inline-start", async () => {
    const onClose = vi.fn()
    const { result } = await renderHook(() =>
      useDrawer({
        closeOnDrag: true,
        open: true,
        placement: "inline-start",
        onClose,
      }),
    )

    const contentProps = result.current.getContentProps()

    contentProps.onDragEnd?.(mockEvent, {
      delta: { x: 0, y: 0 },
      offset: { x: 0, y: 0 },
      point: { x: 0, y: 0 },
      velocity: { x: -200, y: 0 },
    })

    expect(onClose).toHaveBeenCalledWith(undefined)
  })

  test("calls onClose when dragged left with sufficient offset for inline-start", async () => {
    const onClose = vi.fn()
    const { result } = await renderHook(() =>
      useDrawer({
        closeOnDrag: true,
        open: true,
        placement: "inline-start",
        onClose,
      }),
    )

    const contentProps = result.current.getContentProps()

    contentProps.onDragEnd?.(mockEvent, {
      delta: { x: 0, y: 0 },
      offset: { x: -100, y: 0 },
      point: { x: 0, y: 0 },
      velocity: { x: 0, y: 0 },
    })

    expect(onClose).toHaveBeenCalledWith(undefined)
  })

  test("calls onClose when dragged right with sufficient velocity for inline-end", async () => {
    const onClose = vi.fn()
    const { result } = await renderHook(() =>
      useDrawer({
        closeOnDrag: true,
        open: true,
        placement: "inline-end",
        onClose,
      }),
    )

    const contentProps = result.current.getContentProps()

    contentProps.onDragEnd?.(mockEvent, {
      delta: { x: 0, y: 0 },
      offset: { x: 0, y: 0 },
      point: { x: 0, y: 0 },
      velocity: { x: 200, y: 0 },
    })

    expect(onClose).toHaveBeenCalledWith(undefined)
  })

  test("calls onClose when dragged right with sufficient offset for inline-end", async () => {
    const onClose = vi.fn()
    const { result } = await renderHook(() =>
      useDrawer({
        closeOnDrag: true,
        open: true,
        placement: "inline-end",
        onClose,
      }),
    )

    const contentProps = result.current.getContentProps()

    contentProps.onDragEnd?.(mockEvent, {
      delta: { x: 0, y: 0 },
      offset: { x: 100, y: 0 },
      point: { x: 0, y: 0 },
      velocity: { x: 0, y: 0 },
    })

    expect(onClose).toHaveBeenCalledWith(undefined)
  })
})

"use client"

import type { FC, PropsWithChildren, ReactNode } from "react"
import type { HTMLProps, HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { ButtonProps } from "../button"
import type { CloseButtonProps } from "../close-button"
import type { FocusLockProps } from "../focus-lock"
import type { HTMLMotionProps, MotionTransitionProps } from "../motion"
import type { PortalProps } from "../portal"
import type { SlideProps } from "../slide"
import type { DrawerStyle } from "./drawer.style"
import type { UseDrawerProps, UseDrawerReturn } from "./use-drawer"
import { AnimatePresence } from "motion/react"
import { useMemo } from "react"
import { RemoveScroll } from "react-remove-scroll"
import { createSlotComponent, styled, cast, isArray, useSplitChildren, wrapOrPassProps } from "@yamada-ui/react"
import { useValue } from "../../hooks/use-value"
import { Button } from "../button"
import { CloseButton } from "../close-button"
import { fadeVariants } from "../fade"
import { FocusLock } from "../focus-lock"
import { motion } from "../motion"
import { Portal } from "../portal"
import { Slide } from "../slide"
import { drawerStyle } from "./drawer.style"
import { useDrawer } from "./use-drawer"

interface ComponentContext
  extends
    Omit<UseDrawerReturn, "getRootProps">,
    Pick<
      DrawerRootProps,
      "duration" | "placement" | "withCloseButton" | "withDragBar"
    > {}

export interface DrawerRootProps
  extends
    ThemeProps<DrawerStyle>,
    Omit<UseDrawerProps, "placement" | "title">,
    Pick<
      FocusLockProps,
      | "autoFocus"
      | "finalFocusRef"
      | "initialFocusRef"
      | "lockFocusAcrossFrames"
      | "restoreFocus"
    >,
    ShorthandDrawerContentProps {
  /**
   * Handle zoom or pinch gestures on iOS devices when scroll locking is enabled.
   *
   * @default false.
   */
  allowPinchZoom?: boolean
  /**
   * If `true`, scrolling will be disabled on the `body` when the drawer opens.
   *
   * @default true
   */
  blockScrollOnMount?: boolean
  /**
   * The animation duration.
   */
  duration?: MotionTransitionProps["duration"]
  /**
   * The modal trigger to use.
   */
  trigger?: ReactNode
  /**
   * If `true`, display the drawer close button.
   *
   * @default true
   */
  withCloseButton?: boolean
  /**
   * If `true`, display the drag bar when `closeOnDrag` is `true`.
   *
   * @default true
   */
  withDragBar?: boolean
  /**
   * If `true`, display the drawer overlay.
   *
   * @default true
   */
  withOverlay?: boolean
  /**
   * Props to be forwarded to the portal component.
   */
  portalProps?: Omit<PortalProps, "children">
  /**
   * Callback function to run side effects after the drawer has closed.
   */
  onCloseComplete?: () => void
}

const {
  ComponentContext,
  PropsContext: DrawerPropsContext,
  useComponentContext,
  usePropsContext: useDrawerPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<DrawerRootProps, DrawerStyle, ComponentContext>(
  "drawer",
  drawerStyle,
)

export { DrawerPropsContext, useDrawerPropsContext }

/**
 * `Drawer` is a component for a panel that appears from the edge of the screen.
 *
 * @see https://yamada-ui.com/docs/components/drawer
 */
export const DrawerRoot = withProvider<"div", DrawerRootProps, "placement">(
  ({
    allowPinchZoom = false,
    autoFocus,
    blockScrollOnMount = true,
    body,
    cancel,
    children,
    closeOnDrag,
    dragConstraints,
    dragElastic,
    dragOffset,
    dragVelocity,
    duration = { enter: 0.4, exit: 0.3 },
    finalFocusRef,
    footer,
    header,
    initialFocusRef,
    lockFocusAcrossFrames = true,
    middle,
    placement: placementProp,
    restoreFocus,
    success,
    title,
    trigger,
    withCloseButton = !closeOnDrag,
    withDragBar = true,
    withOverlay = true,
    portalProps,
    onCancel,
    onCloseComplete,
    onMiddle,
    onSuccess,
    ...props
  }) => {
    const placement = useValue(placementProp)
    const [omittedChildren, openTrigger, customOverlay] = useSplitChildren(
      children,
      DrawerOpenTrigger,
      DrawerOverlay,
    )
    const hasChildren = isArray(omittedChildren) && !!omittedChildren.length
    const { open, getRootProps, ...rest } = useDrawer({
      closeOnDrag,
      dragConstraints,
      dragElastic,
      dragOffset,
      dragVelocity,
      placement,
      ...props,
    })
    const customOpenTrigger = trigger ? (
      <DrawerOpenTrigger>{trigger}</DrawerOpenTrigger>
    ) : null

    const context = useMemo(
      () => ({
        duration,
        open,
        placement,
        withCloseButton,
        withDragBar,
        ...rest,
      }),
      [duration, open, withDragBar, placement, withCloseButton, rest],
    )

    return (
      <ComponentContext value={context}>
        {openTrigger ?? customOpenTrigger}

        <AnimatePresence onExitComplete={onCloseComplete}>
          {open ? (
            <Portal {...portalProps}>
              <FocusLock
                autoFocus={autoFocus}
                finalFocusRef={finalFocusRef}
                initialFocusRef={initialFocusRef}
                lockFocusAcrossFrames={lockFocusAcrossFrames}
                restoreFocus={restoreFocus}
              >
                <RemoveScroll
                  allowPinchZoom={allowPinchZoom}
                  enabled={blockScrollOnMount}
                  forwardProps
                >
                  <styled.div {...getRootProps()}>
                    {customOverlay ?? (withOverlay ? <DrawerOverlay /> : null)}

                    {hasChildren ? (
                      omittedChildren
                    ) : (
                      <ShorthandDrawerContent
                        body={body}
                        cancel={cancel}
                        footer={footer}
                        header={header}
                        middle={middle}
                        success={success}
                        title={title}
                        onCancel={onCancel}
                        onMiddle={onMiddle}
                        onSuccess={onSuccess}
                      />
                    )}
                  </styled.div>
                </RemoveScroll>
              </FocusLock>
            </Portal>
          ) : null}
        </AnimatePresence>
      </ComponentContext>
    )
  },
  "root",
  { transferProps: ["placement"] },
)()

